    this.originalImage=null;
    this.selectedObjects=[];
    this.initialize();
  }
  initialize(){
    document.getElementById('uploadLabel').addEventListener('click',()=>document.getElementById('imageInput').click());
    document.getElementById('imageInput').addEventListener('change',(e)=>this.loadImage(e.target.files[0]));
    this.canvas.addEventListener('click',(e)=>this.selectObject(e));
    ['colorTolerance','edgeSmoothing'].forEach(id=>{
