    document.getElementById('processBtn').addEventListener('click',()=>this.processSelections());
    document.getElementById('downloadBtn').addEventListener('click',()=>this.downloadSelections());
    this.updateSliderValues();
  }
  updateSliderValues(){
    document.getElementById('colorTolValue').textContent=document.getElementById('colorTolerance').value;
    document.getElementById('smoothingValue').textContent=document.getElementById('edgeSmoothing').value;
