<script>
class MobileImageCutter {
constructor() {
this.canvas=document.getElementById('canvas');
this.ctx=this.canvas.getContext('2d');
this.overlay=document.getElementById('overlayCanvas');
this.octx=this.overlay.getContext('2d');
this.originalData=null;
this.selectedColors=[];
this.zoom=1;
this.offsetX=0;
this.offsetY=0;
this.initialize();
}
initialize() {
const uploadLabel=document.getElementById('uploadLabel');
const input=document.getElementById('imageInput');
uploadLabel.addEventListener('click',e=>{e.preventDefault();input.click();});
input.addEventListener('change',e=>{if(e.target.files[0])this.loadImage(e.target.files[0]);});

this.canvas.addEventListener('click',e=>this.selectColor(e));
this.canvas.addEventListener('touchstart',e=>{e.preventDefault();const t=e.touches[0];const r=this.canvas.getBoundingClientRect();this.selectColor({offsetX:(t.clientX-r.left)*(this.canvas.width/r.width), offsetY:(t.clientY-r.top)*(this.canvas.height/r.height)});});

['colorTolerance','saturationTolerance','brightnessTolerance','minSize','edgeSmoothing'].forEach(id=>{document.getElementById(id).addEventListener('input',()=>{this.updateSliders();if(this.selectedColors.length>0)this.updateOverlay();});});

document.getElementById('undoBtn').addEventListener('click',()=>this.undo());
document.getElementById('clearBtn').addEventListener('click',()=>this.clearSelections());
document.getElementById('processBtn').addEventListener('click',()=>this.processObjects());
document.getElementById('downloadBtn').addEventListener('click',()=>this.downloadObjects());

document.getElementById('zoomIn').addEventListener('click',()=>this.zoomCanvas(1.2));
document.getElementById('zoomOut').addEventListener('click',()=>this.zoomCanvas(0.8));
document.getElementById('resetZoom').addEventListener('click',()=>this.resetZoom());

this.updateSliders();
}
updateSliders() {
document.getElementById('colorTolValue').textContent=document.getElementById('colorTolerance').value;
document.getElementById('satTolValue').textContent=document.getElementById('saturationTolerance').value;
document.getElementById('brightTolValue').textContent=document.getElementById('brightnessTolerance').value;
document.getElementById('minSizeValue').textContent=document.getElementById('minSize').value;
document.getElementById('smoothingValue').textContent=document.getElementById('edgeSmoothing').value;
}
loadImage(file) {
const reader=new FileReader();
reader.onload=e=>{
const img=new Image();
img.onload=()=>{
const maxW=560,maxH=400;
let w=img.width,h=img.height;
if(w>maxW||h>maxH){const ratio=Math.min(maxW/w,maxH/h);w*=ratio;h*=ratio;}
this.canvas.width=this.overlay.width=w;
this.canvas.height=this.overlay.height=h;
this.ctx.drawImage(img,0,0,w,h);
this.originalData=this.ctx.getImageData(0,0,w,h);
document.getElementById('imageContainer').style.display='block';
document.getElementById('controls').style.display='block';
this.status('Image loaded! Tap colors to select.','info');
};
img.src=e.target.result;
};
reader.readAsDataURL(file);
}
selectColor(event) {
if(!this.originalData)return;
const x=Math.floor(event.offsetX),y=Math.floor(event.offsetY);
