const idx=(y*this.canvas.width+x)*4;
const r=this.originalData.data[idx],g=this.originalData.data[idx+1],b=this.originalData.data[idx+2];
this.selectedColors.push({r,g,b,pos:[x,y]});
this.drawPoint(x,y);
this.updateOverlay();
this.status(`Selected color RGB(${r},${g},${b}) - ${this.selectedColors.length} colors`, 'info');
}
drawPoint(x,y){
this.octx.fillStyle='#ff0000';
this.octx.strokeStyle='#fff';
this.octx.lineWidth=2;
this.octx.beginPath();
this.octx.arc(x,y,6,0,2*Math.PI);
this.octx.fill();
this.octx.stroke();
}
updateOverlay(){
if(!this.originalData)return;
this.octx.clearRect(0,0,this.overlay.width,this.overlay.height);
this.selectedColors.forEach(c=>this.drawPoint(c.pos[0],c.pos[1]));
// Placeholder for smart cut suggestion outline
if(document.getElementById('smartToggle').checked){
this.octx.strokeStyle='rgba(0,0,0,0.6)';
this.octx.lineWidth=2;
this.octx.setLineDash([6,3]);
this.octx.strokeRect(10,10,this.canvas.width-20,this.canvas.height-20);
this.octx.setLineDash([]);
}
}
undo(){if(this.selectedColors.length>0)this.selectedColors.pop();this.updateOverlay();}
clearSelections(){this.selectedColors=[];this.updateOverlay();}
processObjects(){document.getElementById('results').style.display='block';const container=document.getElementById('extractedObjects');container.innerHTML='';if(!this.originalData)return;const objCanvas=document.createElement('canvas');objCanvas.width=this.canvas.width;objCanvas.height=this.canvas.height;const objCtx=objCanvas.getContext('2d');objCtx.putImageData(this.originalData,0,0);this.selectedColors.forEach(c=>{objCtx.globalCompositeOperation='destination-in';objCtx.fillStyle=`rgba(${c.r},${c.g},${c.b},1)`;objCtx.fillRect(0,0,objCanvas.width,objCanvas.height);});const imgEl=document.createElement('img');imgEl.src=objCanvas.toDataURL('image/png');const link=document.createElement('button');link.textContent='Download';link.className='download-btn';link.onclick=()=>{const a=document.createElement('a');a.href=imgEl.src;a.download='object.png';a.click();};const div=document.createElement('div');div.className='object-preview';div.appendChild(imgEl);div.appendChild(link);container.appendChild(div);}
downloadObjects(){this.processObjects();}
zoomCanvas(f){this.zoom*=f;this.ctx.setTransform(this.zoom,0,0,this.zoom,this.offsetX,this.offsetY);this.ctx.putImageData(this.originalData,0,0);}
resetZoom(){this.zoom=1;this.offsetX=0;this.offsetY=0;this.ctx.setTransform(1,0,0,1,0,0);this.ctx.putImageData(this.originalData,0,0);}
status(msg,type){const s=document.getElementById('statusMessage');s.textContent=msg;s.className='status '+type;}
}
const cutter=new MobileImageCutter();
</script>
</body>
