# -------- Presenter (formats human-level outputs) --------
class Presenter:
    def __init__(self, mode: str = "observer", verbosity: str = "simple"):
        self.mode = mode  # observer | narrator | assistant | silent
        self.verbosity = verbosity  # simple | verbose

    def set_mode(self, mode: str):
        self.mode = mode

    def set_verbosity(self, verbosity: str):
        self.verbosity = verbosity

    def callout(self, desc_text: str, bind: Optional[Dict[str, Any]]) -> str:
        if self.mode == "silent":
            return ""
        # Base line from descriptor (e.g., "red scene, motion=0.23")
        base = ""
        if self.mode in ("observer", "assistant"):
            base = f"{desc_text.split(',')[0]}" if desc_text else ""
        elif self.mode == "narrator":
            base = desc_text

        bind_line = ""
        if bind and bind.get("binding"):
            b = bind["binding"]
            if b.get("unified"):
                bind_line = b["unified"]
            else:
                strength = b.get("strength")
                mems = b.get("members") or []
                bind_line = f"Binding {strength:.2f} · {len(mems)} items linked" if strength is not None else f"{len(mems)} items linked"

        # Compose
        if base and bind_line:
            text = f"{base} — {bind_line}"
        else:
            text = base or bind_line

        if self.mode == "assistant" and text:
            text += " · Say 'focus' or 'alert' to act"
        return text

    def summary(self, events: List[Dict[str, Any]], window_s: float = 10.0) -> str:
        if not events:
            return "No recent activity."
        now = time.time()
        recent = [e for e in events if (now - float(e.get("t1", now))) <= window_s]
        persons = len([e for e in recent if "person" in (e.get("what") or "")])
        moves = len([e for e in recent if "ingested" in e.get("action","")])
        return f"Past {int(window_s)}s: {persons} person-like events; {moves} observations."

