# ===================== TrueVision (public API) =====================
class TrueVision:
    """
    Public-facing API that:
      - Maintains CLIENT-SIDE continuity & sessions (no engine leak)
      - Proxies semantic evolution, binding, and foresight to your engine
      - Supports LIVE VIDEO FEEDS with an on-screen visual responder
      - Supports AUDIO descriptors for multi-sensor fusion
      - Formats human-level outputs via Presenter
    """
    def __init__(self, mode: str = "local", **kwargs):
        if mode == "local":
            self.engine = LocalCrystalEngineClient()
        elif mode == "remote":
            self.engine = RemoteCrystalEngineClient(kwargs["base_url"], kwargs["api_key"], kwargs.get("request_fn"))
        else:
            raise ValueError("mode must be 'local' or 'remote'")

        # Continuity/session state
        self._session_id: Optional[str] = None
        self._continuity: Dict[str, Dict[str, Any]] = {}
        self._concept_to_crystal: Dict[str, Optional[str]] = {}
        self._lock = threading.Lock()

        # Video responder config
        self._video_running = False
        self._video_thread: Optional[threading.Thread] = None
        self._overlay_enabled = True
        self._frame_sampler_hz = kwargs.get("frame_sampler_hz", 6)
        self._last_processed_ts = 0.0

        # Presenter
        self.presenter = Presenter(mode=kwargs.get("mode", "observer"),
                                   verbosity=kwargs.get("verbosity", "simple"))

    # ---- Mode / verbosity ----
    def set_mode(self, mode: str):
        self.presenter.set_mode(mode)

    def set_verbosity(self, verbosity: str):
        self.presenter.set_verbosity(verbosity)

    # ---- Session / continuity control ----
    def start_session(self, session_id: Optional[str] = None):
        with self._lock:
            self._session_id = session_id or f"sess_{uuid.uuid4().hex[:8]}"
            self._continuity.clear()
            self._concept_to_crystal.clear()
        return {"session_id": self._session_id}

    def end_session(self):
        with self._lock:
            sid = self._session_id
            self._session_id = None
            self._continuity.clear()
            self._concept_to_crystal.clear()
        return {"ended": True, "session_id": sid}

    # ---- Helpers ----
    def _derive_concept_key(self, text: str) -> str:
        tokens = [t for t in text.strip().split() if t]
        return " ".join(tokens[:3]) if tokens else "observation"

    def _touch_continuity(self, concept_key: str) -> str:
        rec = self._continuity.get(concept_key)
        if not rec:
            rec = {"id": f"cid_{uuid.uuid4().hex[:8]}", "hits": 0}
        rec["last"] = time.time(); rec["hits"] += 1
        self._continuity[concept_key] = rec
        return rec["id"]

    # ---- Public API (text/dict) ----
    def see(self, input_: Union[str, Dict[str, Any]], context: str = "") -> Dict[str, Any]:
        if isinstance(input_, dict):
            text = str(input_.get("text", ""))
            concept_key = input_.get("concept_key") or self._derive_concept_key(text)
        else:
            text = str(input_)
            concept_key = self._derive_concept_key(text)

        continuity_id = self._touch_continuity(concept_key)
        payload = {"text": text, "context": context, "concept_key": concept_key,
                   "continuity_id": continuity_id, "session_id": self._session_id, "t0": time.time()}
        out = self.engine.ingest(payload)
        cid = out.get("crystal_id")
        if cid is not None:
            self._concept_to_crystal[concept_key] = cid
        return {**out, "continuity_id": continuity_id, "session_id": self._session_id}

    def hear(self, audio_desc: dict, context: str = "mic") -> dict:
        speaker = audio_desc.get("speaker_id", "spk_a")
        concept_key = audio_desc.get("concept_key") or f"voice {speaker}"
        continuity_id = self._touch_continuity(concept_key)
        payload = {**audio_desc, "concept_key": concept_key, "continuity_id": continuity_id,
                   "session_id": self._session_id, "context": context, "t0": time.time()}
        out = self.engine.ingest_audio(payload)
        cid = out.get("crystal_id")
        if cid is not None:
            self._concept_to_crystal[concept_key] = cid
        return {**out, "continuity_id": continuity_id, "session_id": self._session_id}

    def understand(self, context: str = "") -> Dict[str, Any]:
        out = self.engine.bind(context=context)
        b = out.get("binding")
        if not b:
            return {"binding": None}
        members = b.get("members", [])
        continuity_map: Dict[str, str] = {}
        if members:
            rev = {v: k for k, v in self._concept_to_crystal.items() if v}
            for m in members:
                ck = rev.get(m)
                if ck and ck in self._continuity:
                    continuity_map[m] = self._continuity[ck]["id"]
        b["continuity_map"] = continuity_map
        b["session_id"] = self._session_id
        return {"binding": b}

    def tell(self) -> Dict[str, Any]:
        return self.engine.narrative()

    def foresight(self, concept: str, perspective: Optional[str] = None) -> Dict[str, Any]:
        out = self.engine.foresight(concept, perspective)
        out["session_id"] = self._session_id
        return out

    # ---- Presentation helpers ----
    def present_callout(self, last_desc_text: str, bind_out: Optional[Dict[str, Any]] = None) -> str:
        return self.presenter.callout(last_desc_text, bind_out)

    def present_summary(self, window_s: float = 10.0) -> str:
        events = self.engine.narrative().get("events", [])
        return self.presenter.summary(events, window_s=window_s)

    # ===================== LIVE VIDEO FEED SUPPORT =====================
    def start_video(self, source: Union[int, str] = 0, overlay: bool = True, descriptor_fn: Optional[Callable[[Any], str]] = None):
        if self._video_running:
            return {"ok": False, "error": "video already running"}
        self._overlay_enabled = overlay

        def _run():
            try:
                import cv2
                cap = cv2.VideoCapture(source)
                if not cap.isOpened():
                    return
                self._video_running = True
                win = "TrueVision"
                if self._overlay_enabled:
                    cv2.namedWindow(win, cv2.WINDOW_NORMAL)
                last_desc = ""
                last_bind = None
                while self._video_running:
                    ok, frame = cap.read()
                    if not ok:
                        break
                    now = time.time()
                    if now - self._last_processed_ts >= 1.0 / max(1, self._frame_sampler_hz):
                        self._last_processed_ts = now
                        desc = descriptor_fn(frame) if descriptor_fn else self._default_descriptor(frame)
                        last_desc = desc
                        bind = self.understand()
                        last_bind = bind
                        # send descriptor AFTER understand to avoid double-lag
                        self.see({"text": desc, "concept_key": self._derive_concept_key(desc)})
                    if self._overlay_enabled:
                        text = self.present_callout(last_desc, last_bind)
                        frame = self._draw_overlay(frame, text)
                        cv2.imshow(win, frame)
                        if (cv2.waitKey(1) & 0xFF) == 27:  # ESC
                            break
                cap.release()
                if self._overlay_enabled:
                    cv2.destroyAllWindows()
            finally:
                self._video_running = False

        self._video_thread = threading.Thread(target=_run, daemon=True)
        self._video_thread.start()
        return {"ok": True}

    def stop_video(self):
        self._video_running = False
        t = self._video_thread
        self._video_thread = None
        if t and t.is_alive():
            t.join(timeout=1.0)
        return {"ok": True}

    def _default_descriptor(self, frame: Any) -> str:
        try:
            import cv2, numpy as np
            gray = cv2.cvtColor(frame, cv2.COLOR_BGR2GRAY)
            edges = cv2.Canny(gray, 80, 160)
            edge_ratio = float((edges > 0).sum()) / max(1, edges.size)
            if not hasattr(self, "_prev_gray"):
                self._prev_gray = gray
            diff = cv2.absdiff(gray, self._prev_gray)
            motion = float(diff.mean()) / 255.0
            self._prev_gray = gray
            hsv = cv2.cvtColor(frame, cv2.COLOR_BGR2HSV)
            h = int(hsv[...,0].mean())
            color = "red" if (h < 10 or h > 170) else "yellow" if h < 35 else "green" if h < 85 else "blue" if h < 130 else "purple"
            return f"{color} scene, edge={edge_ratio:.2f}, motion={motion:.2f}"
        except Exception:
            return "scene observed"

    def _draw_overlay(self, frame: Any, text: str):
        try:
            import cv2
            if not text:
                return frame
            h, w = frame.shape[:2]
            overlay = frame.copy()
            cv2.rectangle(overlay, (0,0), (w, 70), (0,0,0), -1)
            alpha = 0.35
            frame = cv2.addWeighted(overlay, alpha, frame, 1-alpha, 0)
            cv2.putText(frame, f"TV: {text[:60]}", (12, 28), cv2.FONT_HERSHEY_SIMPLEX, 0.6, (255,255,255), 1, cv2.LINE_AA)
            return frame
        except Exception:
            return frame
''')

