remote_client_py = dedent('''
# truevision_remote_client.py
# HTTP wiring for RemoteCrystalEngineClient used by TruVision SDK.

import json, time
from typing import Any, Dict, Optional
import urllib.request

class RemoteCrystalEngineClient:
    def __init__(self, base_url: str, api_key: str):
        self.base_url = base_url.rstrip("/")
        self.api_key = api_key

    def _post(self, path: str, payload: Dict[str, Any]) -> Dict[str, Any]:
        url = f"{self.base_url}{path}"
        data = json.dumps(payload).encode("utf-8")
        req = urllib.request.Request(url, data=data, method="POST")
        req.add_header("Content-Type", "application/json")
        req.add_header("X-API-Key", self.api_key)
        with urllib.request.urlopen(req, timeout=10) as resp:
            return json.loads(resp.read().decode("utf-8"))

    def _get(self, path: str) -> Dict[str, Any]:
        url = f"{self.base_url}{path}"
        req = urllib.request.Request(url, method="GET")
        req.add_header("X-API-Key", self.api_key)
        with urllib.request.urlopen(req, timeout=10) as resp:
            return json.loads(resp.read().decode("utf-8"))

    def ingest(self, payload: Dict[str, Any]) -> Dict[str, Any]:
        payload = dict(payload)
        payload.setdefault("t0", time.time())
        return self._post("/ingest", payload)

    def ingest_audio(self, payload: Dict[str, Any]) -> Dict[str, Any]:
        payload = dict(payload)
        payload.setdefault("t0", time.time())
        return self._post("/ingest_audio", payload)

    def bind(self, context: str = "") -> Dict[str, Any]:
        return self._post("/bind", {"context": context})

    def narrative(self) -> Dict[str, Any]:
        return self._get("/narrative")

    def foresight(self, concept: str, perspective: Optional[str] = None) -> Dict[str, Any]:
        return self._post("/foresight", {"concept": concept, "perspective": perspective})
''')

test_page_html = dedent('''
<!-- test_page.html
A local page that captures webcam + mic, derives tiny descriptors, then POSTs to your local Engine API server.
No raw media leaves the browser. Open via a local HTTP server (python -m http.server).
-->
<!doctype html>
<html>
<head>
  <meta charset="utf-8" />
  <title>TruVizion — Live Eyes + Ears</title>
  <style>
    body { font-family: system-ui, Arial, sans-serif; margin: 0; }
    header { padding: 10px 14px; background: #111; color: #fff; }
    main { display: grid; grid-template-columns: 1fr 360px; gap: 12px; padding: 12px; }
    #log { height: 70vh; overflow: auto; border: 1px solid #ccc; padding: 8px; font-family: ui-monospace, SFMono-Regular, monospace; }
    canvas, video { max-width: 100%; background: #000; }
    .row { display: flex; gap: 8px; align-items: center; flex-wrap: wrap; }
    .pill { background: #eee; padding: 4px 8px; border-radius: 999px; }
  </style>
</head>
<body>
  <header>
    <strong>TruVizion Live Test</strong>
  </header>
  <main>
    <section>
      <div class="row">
        <button id="start">Start</button>
        <button id="stop">Stop</button>
        <span class="pill">Sampling: <span id="hz">6</span> Hz</span>
        <span class="pill">API: <input id="api" value="http://127.0.0.1:8787" size="24"/></span>
        <span class="pill" id="micStatus">Mic: off</span>
      </div>
      <video id="vid" playsinline autoplay muted></video>
      <canvas id="c" width="640" height="360" hidden></canvas>
    </section>
    <aside>
      <div id="log"></div>
    </aside>
  </main>
  <script>
    const vid = document.getElementById('vid');
    const c = document.getElementById('c');
    const ctx = c.getContext('2d');
    const log = document.getElementById('log');
    const startBtn = document.getElementById('start');
    const stopBtn = document.getElementById('stop');
    const apiEl = document.getElementById('api');
    const micStatus = document.getElementById('micStatus');

    let timer = null, lastFrame = null, sessionId = 'sess_' + Math.random().toString(16).slice(2,10);
    const FPS = 6;

    // --- Audio capture state ---
    let audioCtx = null, micStream = null, analyser = null, timeData = null;

    function append(msg){
      const el = document.createElement('div');
      el.textContent = msg;
      log.prepend(el);
    }

    async function capture(){
      if (!vid.srcObject) return;
      const w = c.width, h = c.height;
      ctx.drawImage(vid, 0, 0, w, h);
      const frame = ctx.getImageData(0,0,w,h);
      const data = frame.data;
      let r=0,g=0,b=0, n=0, md=0;
      for (let i=0;i<data.length;i+=40){
        r+=data[i]; g+=data[i+1]; b+=data[i+2]; n++;
        if (lastFrame){
          const d = Math.abs(data[i] - lastFrame.data[i]) + Math.abs(data[i+1]-lastFrame.data[i+1]) + Math.abs(data[i+2]-lastFrame.data[i+2]);
          md += d;
        }
      }
      if (lastFrame) md = md / (n*255*3);
      lastFrame = frame;
      const avgR=r/n, avgG=g/n, avgB=b/n;
      const color = dominantColor(avgR,avgG,avgB);
      const desc = `${color} scene, motion=${(md||0).toFixed(2)}`;
      const concept_key = desc.split(',')[0];

      try{
        const base = apiEl.value.replace(/\\/$/,'');

        // VIDEO → /ingest
        const res = await fetch(base + '/ingest', {
          method: 'POST', headers: {'Content-Type':'application/json'},
          body: JSON.stringify({text: desc, context: 'webcam', concept_key, session_id: sessionId, t0: Date.now()/1000})
        });
        const out = await res.json();
        append(`SEE → ${out.concept} (ok=${out.ok})`);

        // AUDIO (if active) → /ingest_audio
        if (analyser && timeData){
          analyser.getFloatTimeDomainData(timeData);
          let sumSq = 0; for (let i=0;i<timeData.length;i++){ const v=timeData[i]; sumSq += v*v; }
          const rms = Math.sqrt(sumSq / timeData.length);
          const energy = Math.min(1, rms * 20);
          await fetch(base + '/ingest_audio', {
            method:'POST', headers:{'Content-Type':'application/json'},
            body: JSON.stringify({
              text: "", // transcript optional
              prosody: { energy },
              emotion: null,
              speaker_id: 'spk_a',
              concept_key: 'voice spk_a',
              session_id: sessionId,
              context: 'mic',
              t0: Date.now()/1000
            })
          });
          append(`HEAR → energy=${energy.toFixed(2)}`);
        }

        // BIND → /bind
        const bres = await fetch(base + '/bind', {method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({context:'webcam+mic'})});
        const bout = await bres.json();
        if (bout.binding && bout.binding.strength!==undefined){
          append(`BIND → strength=${bout.binding.strength.toFixed(2)} members=${(bout.binding.members||[]).length}`);
        }
      }catch(e){ append('ERR ' + e); }
    }

    function dominantColor(r,g,b){
      const max = Math.max(r,g,b);
      if (max===r) return 'red';
      if (max===g) return 'green';
      return 'blue';
    }

    startBtn.onclick = async ()=>{
      // VIDEO
      const vstream = await navigator.mediaDevices.getUserMedia({video:true, audio:false});
      vid.srcObject = vstream;
      // AUDIO (optional, best effort)
      try{
        micStream = await navigator.mediaDevices.getUserMedia({audio:true});
        audioCtx = new (window.AudioContext || window.webkitAudioContext)();
        const src = audioCtx.createMediaStreamSource(micStream);
        analyser = audioCtx.createAnalyser();
        analyser.fftSize = 2048;
        timeData = new Float32Array(analyser.fftSize);
        src.connect(analyser);
        micStatus.textContent = 'Mic: on';
      }catch(e){
        micStatus.textContent = 'Mic: unavailable';
      }
      timer = setInterval(capture, 1000/FPS);
      append('Session ' + sessionId + ' started');
    };

    stopBtn.onclick = ()=>{
      if (vid.srcObject){ vid.srcObject.getTracks().forEach(t=>t.stop()); vid.srcObject=null; }
      if (micStream){ micStream.getTracks().forEach(t=>t.stop()); micStream=null; }
      if (audioCtx){ audioCtx.close(); audioCtx=null; analyser=null; timeData=null; }
      clearInterval(timer); timer=null; lastFrame=null;
      micStatus.textContent = 'Mic: off';
      append('Session stopped');
    };
  </script>
</body>
</html>
''')

